module RefModule(
    input clk,
    input d,
    input sr,
    output reg q,
    output reg qn
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge sr or posedge dbg_halt)
begin
    if (~sr)
        q <= 0;
    else
        q <= d;
end

always @(posedge clk or negedge sr)
begin
    if (~sr)
        qn <= 1;
    else
        qn <= ~d;
end

endmodule
